def oh(c):
    keys = ['app', 'web']
    if c in keys:
        return {k: int(k == c) for k in keys} | {'unknown': 0}
    return {k: 0 for k in keys} | {'unknown': 1}
print(oh('app'), oh('sms'))

def pipe(xs):
    return [((0 if x is None else x) * 2) for x in xs]
print(pipe([None, 3]))
